# Tool wrapper offloads when its output is large.
def web_search(query: str) -> dict:
    raw = provider.search(query)            # full HTML/JSON response
    if token_count(raw) > 2000:
        path = fs.write(f"search/{slug(query)}.json", raw)
        return {"path": path, "head": raw[:600], "kind": "offloaded"}
    return {"inline": raw, "kind": "inline"}
